// cvdp_copilot_apb_gpio.v

module cvdp_copilot_apb_gpio #(
  parameter GPIO_WIDTH = 8
)(
  // Clock and Reset Signals
  input wire pclk,       // Clock signal
  input wire preset_n,   // Active-low reset signal

  // APB Interface Inputs
  input wire psel,           // Peripheral select
  input wire [7:2] paddr,    // APB address bus (bits [7:2])
  input wire penable,        // Transfer control signal
  input wire pwrite,         // Write control signal
  input wire [31:0] pwdata,  // Write data bus

  // APB Interface Outputs
  output reg [31:0] prdata, // Read data bus
  output wire pready,        // Device ready signal
  output wire pslverr,       // Device error response

  // Bidirectional GPIO Interface
  inout wire [GPIO_WIDTH-1:0] gpio, // Bidirectional GPIO pins

  // Interrupt Outputs
  output reg [GPIO_WIDTH-1:0] gpio_int, // Individual interrupt outputs
  output reg comb_int                   // Combined interrupt output
);

  // Signals for Read/Write Controls
  wire read_enable;                     // Read enable signal
  wire write_enable;                    // Write enable signal
  reg write_enable_reg_04;              // Write enable for Data Output register
  reg write_enable_reg_08;              // Write enable for Output Enable register
  reg write_enable_reg_0C;              // Write enable for Interrupt Enable register
  reg write_enable_reg_10;              // Write enable for Interrupt Type register
  reg write_enable_reg_14;              // Write enable for Interrupt Polarity register
  reg write_enable_reg_18;              // Write enable for Interrupt State register
  reg write_enable_reg_1C;              // Write enable for Direction Control register
  reg write_enable_reg_20;              // Write enable for Power Down register
  reg write_enable_reg_24;              // Write enable for Interrupt Control register
  reg [GPIO_WIDTH-1:0] read_mux;        // Read data multiplexer
  reg [GPIO_WIDTH-1:0] read_mux_d1;     // Registered read data

  // Control Registers
  reg [GPIO_WIDTH-1:0] reg_dout;        // Data Output register
  reg [GPIO_WIDTH-1:0] reg_dout_en;     // Output Enable register (kept for compatibility)
  reg [GPIO_WIDTH-1:0] reg_int_en;      // Interrupt Enable register
  reg [GPIO_WIDTH-1:0] reg_int_type;    // Interrupt Type register
  reg [GPIO_WIDTH-1:0] reg_int_pol;     // Interrupt Polarity register
  reg [GPIO_WIDTH-1:0] reg_int_state;   // Interrupt State register
  reg [GPIO_WIDTH-1:0] reg_gpio_dir;    // Direction Control register (1: output, 0: input)
  reg reg_power_down;                   // Power Down register
  reg reg_int_ctrl;                     // Interrupt Control register

  // I/O Signal Path and Interrupt Logic
  reg [GPIO_WIDTH-1:0] data_in_sync1;            // First stage of input synchronization
  reg [GPIO_WIDTH-1:0] data_in_sync2;            // Second stage of input synchronization
  wire [GPIO_WIDTH-1:0] data_in_pol_adjusted;    // Polarity-adjusted input data
  reg [GPIO_WIDTH-1:0] data_in_pol_adjusted_dly; // Delayed version of polarity-adjusted input data
  wire [GPIO_WIDTH-1:0] edge_detect;             // Edge detection signals
  wire [GPIO_WIDTH-1:0] raw_int;                 // Raw interrupt signals
  wire [GPIO_WIDTH-1:0] int_masked;              // Masked interrupt signals
  wire [GPIO_WIDTH-1:0] clear_interrupt;         // Clear interrupt signals

  // Internal Signals
  wire module_active;                 // Module active signal based on power-down
  wire [GPIO_WIDTH-1:0] gpio_in_int;  // Internal GPIO input signals

  // Read and Write Control Signals
  assign read_enable = psel & (~pwrite); // Read enable
  assign write_enable = psel & (~penable) & pwrite; // Write enable

  // Write Enable Signals for Specific Registers
  always @(*) begin
    write_enable_reg_04 = write_enable & (paddr[7:2] == 6'd1);  // Address 0x04
    write_enable_reg_08 = write_enable & (paddr[7:2] == 6'd2);  // Address 0x08
    write_enable_reg_0C = write_enable & (paddr[7:2] == 6'd3);  // Address 0x0C
    write_enable_reg_10 = write_enable & (paddr[7:2] == 6'd4);  // Address 0x10
    write_enable_reg_14 = write_enable & (paddr[7:2] == 6'd5);  // Address 0x14
    write_enable_reg_18 = write_enable & (paddr[7:2] == 6'd6);  // Address 0x18
    write_enable_reg_1C = write_enable & (paddr[7:2] == 6'd7);  // Address 0x1C
    write_enable_reg_20 = write_enable & (paddr[7:2] == 6'd8);  // Address 0x20
    write_enable_reg_24 = write_enable & (paddr[7:2] == 6'd9);  // Address 0x24
  end

  // Module Active Signal Based on Power-Down Register
  assign module_active = ~reg_power_down;

  // Write Operations for Control Registers

  // Data Output Register (reg_dout)
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_04)
        reg_dout <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  // Output Enable Register (reg_dout_en) - Kept for Compatibility
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout_en <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_08)
        reg_dout_en <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  // Interrupt Enable Register (reg_int_en)
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_en <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_0C)
        reg_int_en <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_type <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_10)
        reg_int_type <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_pol <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_14)
        reg_int_pol <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  // Direction Control Register (reg_gpio_dir)
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_gpio_dir <= {GPIO_WIDTH{1'b0}};
    else if (module_active) begin
      if (write_enable_reg_1C)
        reg_gpio_dir <= pwdata[(GPIO_WIDTH-1):0];
    end
  end

  // Power Down Register (reg_power_down)
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_power_down <= 1'b0;
    else begin
      if (write_enable_reg_20)
        reg_power_down <= pwdata[0];
    end
  end

  // Interrupt Control Register (reg_int_ctrl)
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_ctrl <= 1'b0;
    else begin
      if (write_enable_reg_24)
        reg_int_ctrl <= pwdata[0];
      else
        reg_int_ctrl <= 1'b0; // Auto-clear after use
    end
  end

  // Read Operation: Multiplexing Register Data Based on Address
  always @(*) begin
    case (paddr[7:2])
      6'd0: read_mux = data_in_sync2;   // Input Data Register at address 0x00
      6'd1: read_mux = reg_dout;        // Data Output Register at address 0x04
      6'd2: read_mux = reg_dout_en;     // Output Enable Register at address 0x08
      6'd3: read_mux = reg_int_en;      // Interrupt Enable Register at address 0x0C
      6'd4: read_mux = reg_int_type;    // Interrupt Type Register at address 0x10
      6'd5: read_mux = reg_int_pol;     // Interrupt Polarity Register at address 0x14
      6'd6: read_mux = reg_int_state;   // Interrupt State Register at address 0x18
      6'd7: read_mux = reg_gpio_dir;    // Direction Control Register at address 0x1C
      6'd8: read_mux = {{(GPIO_WIDTH-1){1'b0}}, reg_power_down}; // Power Down Register at address 0x20
      6'd9: read_mux = {{(GPIO_WIDTH-1){1'b0}}, reg_int_ctrl};   // Interrupt Control Register at address 0x24
      default: read_mux = {GPIO_WIDTH{1'b0}}; // Default to zeros if address is invalid
    endcase
  end

  // Registering Read Data for Timing Alignment
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      read_mux_d1 <= {GPIO_WIDTH{1'b0}};
    else
      read_mux_d1 <= read_mux;
  end

  // Output Read Data to APB Interface
  always @(*) begin
    if (read_enable)
      prdata = {{(32-GPIO_WIDTH){1'b0}}, read_mux_d1};
    else
      prdata = {32{1'b0}};
  end

  assign pready = 1'b1; // Always ready
  assign pslverr = 1'b0; // No error

  // Driving GPIO Outputs and Direction Control
  genvar i;
  generate
    for (i = 0; i < GPIO_WIDTH; i = i + 1) begin : gpio_buffer
      assign gpio[i] = (reg_gpio_dir[i] && module_active) ? reg_dout[i] : 1'bz; // Drive when output
    end
  endgenerate

  assign gpio_in_int = gpio; // Read the gpio pins

  // Input Synchronization to Avoid Metastability
  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_sync1 <= {GPIO_WIDTH{1'b0}};
      data_in_sync2 <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_sync1 <= gpio_in_int;
      data_in_sync2 <= data_in_sync1;
    end
  end

  assign data_in_pol_adjusted = ~(data_in_sync2 ^ reg_int_pol); 

  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_pol_adjusted_dly <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_pol_adjusted_dly <= data_in_pol_adjusted;
    end
  end

  assign edge_detect = data_in_pol_adjusted & (~data_in_pol_adjusted_dly); // Rising edge detection

  assign raw_int = (reg_int_type & edge_detect) | (~reg_int_type & data_in_pol_adjusted); // Interrupt source

  // Applying Interrupt Enable Mask
  assign int_masked = raw_int & reg_int_en; // Masked interrupts

  // Clear Interrupt Signals
  assign clear_interrupt = pwdata[GPIO_WIDTH-1:0] & {GPIO_WIDTH{write_enable_reg_18}};

  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      reg_int_state <= {GPIO_WIDTH{1'b0}};
    end else begin
      integer idx;
      for (idx = 0; idx < GPIO_WIDTH; idx = idx + 1) begin
        if (~module_active) begin
          // Clear interrupt state when module is inactive
          reg_int_state[idx] <= 1'b0;
        end else if (reg_int_ctrl) begin
          // Software-controlled reset for all interrupts
          reg_int_state[idx] <= 1'b0;
        end else begin
          if (reg_int_type[idx]) begin
            // Edge-triggered interrupt
            if (clear_interrupt[idx]) begin
              reg_int_state[idx] <= 1'b0;
            end else if (int_masked[idx]) begin
              reg_int_state[idx] <= 1'b1;
            end
          end else begin
            // Level-triggered interrupt
            reg_int_state[idx] <= int_masked[idx];
          end
        end
      end
    end
  end

  always @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      gpio_int <= {GPIO_WIDTH{1'b0}};
      comb_int <= 1'b0;
    end else begin
      gpio_int <= reg_int_state;     // Individual interrupt outputs
      comb_int <= |reg_int_state;    // Combined interrupt output
    end
  end

endmodule

input.verif/cvdp_copilot_apb_gpio_tb.sv:
`timescale 1ns/1ps

module cvdp_copilot_apb_gpio_tb;

  // Parameters
  parameter GPIO_WIDTH = 8;

  // Clock and Reset Signals
  reg pclk;               // Clock signal
  reg preset_n;           // Active-low reset signal

  // APB Interface Signals
  reg psel;               // Peripheral select signal
  reg [7:2] paddr;        // APB address bus
  reg penable;            // Transfer control signal
  reg pwrite;             // Write control signal
  reg [31:0] pwdata;      // Write data bus
  wire [31:0] prdata;     // Read data bus
  wire pready;            // Device ready signal
  wire pslverr;           // Device error signal

  // Bidirectional GPIO Interface Signals
  wire [GPIO_WIDTH-1:0] gpio; // Bidirectional GPIO pins

  // Internal Variables for GPIO Simulation
  logic [GPIO_WIDTH-1:0] gpio_drive;    // Signals driven onto GPIO pins by the testbench
  logic [GPIO_WIDTH-1:0] gpio_drive_en; // Enable signals for driving GPIOs
  wire [GPIO_WIDTH-1:0] gpio_in_tb;     // Signals read from GPIO pins by the testbench

  // Interrupt Signals
  wire [GPIO_WIDTH-1:0] gpio_int; // Individual interrupt outputs
  wire comb_int;                  // Combined interrupt output

  // Internal Variables
  integer i;
  reg [31:0] read_data; // For storing read data
  reg test_passed;      // Flag to indicate test pass/fail

  // Instantiate the DUT (Device Under Test)
  cvdp_copilot_apb_gpio #(
    .GPIO_WIDTH(GPIO_WIDTH)
  ) dut (
    .pclk(pclk),
    .preset_n(preset_n),
    .psel(psel),
    .paddr(paddr),
    .penable(penable),
    .pwrite(pwrite),
    .pwdata(pwdata),
    .prdata(prdata),
    .pready(pready),
    .pslverr(pslverr),
    .gpio(gpio),
    .gpio_int(gpio_int),
    .comb_int(comb_int)
  );

  // Modeling Bidirectional GPIOs
  // Assigning 'z' when testbench is not driving the GPIO pins
  genvar idx;
  generate
    for (idx = 0; idx < GPIO_WIDTH; idx = idx + 1) begin : gpio_model
      assign gpio[idx] = (gpio_drive_en[idx]) ? gpio_drive[idx] : 1'bz;
      assign gpio_in_tb[idx] = gpio[idx];
    end
  endgenerate

  // Clock Generation: 50 MHz Clock (Period = 20 ns)
  initial begin
    pclk = 0;
    forever #10 pclk = ~pclk;
  end

  // Reset Generation
  initial begin
    preset_n = 0;
    #50; // Hold reset low for 50 ns
    preset_n = 1;
  end

  // VCD Dump for Waveform Viewing
  initial begin
    $dumpfile("cvdp_copilot_apb_gpio_tb.vcd");
    $dumpvars(0, cvdp_copilot_apb_gpio_tb);
  end

  // APB Read Task
  task apb_read;
    input [7:2] address;
    output [31:0] data;
    begin
      @ (posedge pclk);
      psel = 1;
      paddr = address;
      pwrite = 0;
      penable = 0;
      @ (posedge pclk);
      penable = 1;
      @ (posedge pclk);
      data = prdata; // Capture data after access phase
      psel = 0;
      penable = 0;
    end
  endtask

  // APB Write Task
  task apb_write;
    input [7:2] address;
    input [31:0] data;
    begin
      @ (posedge pclk);
      psel = 1;
      paddr = address;
      pwrite = 1;
      pwdata = data;
      penable = 0;
      @ (posedge pclk);
      penable = 1;
      @ (posedge pclk);
      psel = 0;
      penable = 0;
    end
  endtask

  // Test Sequence
  initial begin
    // Initialize APB Signals
    psel = 0;
    paddr = 0;
    penable = 0;
    pwrite = 0;
    pwdata = 0;

    // Initialize GPIO Drive Signals
    gpio_drive = {GPIO_WIDTH{1'b0}};
    gpio_drive_en = {GPIO_WIDTH{1'b0}};

    // Wait for Reset Deassertion
    wait(preset_n == 1);

    // Wait for a few clock cycles
    repeat (5) @ (posedge pclk);

    // Test 1: Bidirectional GPIOs - Configure Directions and Verify I/O
    $display("\nTest 1: Bidirectional GPIOs - Direction Control");
    // Configure GPIO[7:4] as outputs, GPIO[3:0] as inputs
    apb_write(6'd7, 32'hF0); // Write to Direction Control Register at 0x1C
    apb_read(6'd7, read_data);
    if (read_data[GPIO_WIDTH-1:0] !== 8'hF0) begin
      $display("FAIL: Direction Control Register mismatch");
    end else begin
      $display("PASS: Direction Control Register set to 0x%0h", read_data[GPIO_WIDTH-1:0]);
    end

    // Write data to outputs
    apb_write(6'd1, 32'hA0); // Data Output Register at 0x04
    apb_read(6'd1, read_data);
    if (read_data[GPIO_WIDTH-1:0] !== 8'hA0) begin
      $display("FAIL: Data Output Register mismatch");
    end else begin
      $display("PASS: Data Output Register value: 0x%0h", read_data[GPIO_WIDTH-1:0]);
    end

    // Verify that GPIO[7:4] are driven by the DUT
    #20; // Wait for GPIO outputs to settle
    for (i = 4; i < 8; i = i + 1) begin
      if (gpio[i] !== ((8'hA0 >> i) & 1'b1)) begin
        $display("FAIL: GPIO[%0d] output mismatch. Expected: %b, Got: %b", i, ((8'hA0 >> i) & 1'b1), gpio[i]);
      end else begin
        $display("PASS: GPIO[%0d] output matches expected value", i);
      end
    end

    // Drive values on GPIO[3:0] and verify input data
    gpio_drive[3:0] = 4'hB;      // Drive 0b1011 on GPIO[3:0]
    gpio_drive_en[3:0] = 4'hF;    // Enable driving on GPIO[3:0]
    repeat (3) @ (posedge pclk); // Wait for synchronization
    apb_read(6'd0, read_data); // Read Input Data Register at 0x00
    if (read_data[3:0] !== 4'hB) begin
      $display("FAIL: GPIO Input Data mismatch on GPIO[3:0]");
    end else begin
      $display("PASS: GPIO Input Data on GPIO[3:0] is 0x%0h", read_data[3:0]);
    end
    gpio_drive_en[3:0] = 4'h0; // Stop driving GPIO[3:0]

    // Test 2: Power Management - Power Down and Power Up
    $display("\nTest 2: Power Management - Power Down and Power Up");
    // Power down the module
    apb_write(6'd8, 32'h1); // Write to Power Down Register at 0x20
    #20; // Wait for module to power down

    // Attempt to change outputs while powered down
    apb_write(6'd1, 32'hFF); // Try to write to Data Output Register
    apb_read(6'd1, read_data);
    if (read_data[GPIO_WIDTH-1:0] !== 8'hA0) begin
      $display("FAIL: Data Output Register changed during power-down");
    end else begin
      $display("PASS: Data Output Register did not change during power-down");
    end

    // Check that GPIO outputs are tri-stated
    #20; // Wait for GPIO outputs to settle
    for (i = 4; i < 8; i = i + 1) begin
      if (gpio[i] !== 1'bz) begin
        $display("FAIL: GPIO[%0d] should be tri-stated during power-down", i);
      end else begin
        $display("PASS: GPIO[%0d] is tri-stated during power-down", i);
      end
    end

    // Power up the module
    apb_write(6'd8, 32'h0); // Write to Power Down Register to power up
    #20; // Wait for module to power up

    // Verify that outputs return to previous state
    for (i = 4; i < 8; i = i + 1) begin
      if (gpio[i] !== ((8'hA0 >> i) & 1'b1)) begin
        $display("FAIL: GPIO[%0d] output mismatch after power-up. Expected: %b, Got: %b", i, ((8'hA0 >> i) & 1'b1), gpio[i]);
      end else begin
        $display("PASS: GPIO[%0d] output restored after power-up", i);
      end
    end

    // Test 3: Software-Controlled Reset for Interrupts
    $display("\nTest 3: Software-Controlled Reset for Interrupts");
    // Configure GPIO[0] for edge-triggered interrupt
    apb_write(6'd4, 32'h01); // Interrupt Type Register at 0x10 (edge-triggered on GPIO[0])
    apb_write(6'd5, 32'h00); // Interrupt Polarity Register at 0x14 (active high)
    apb_write(6'd3, 32'h01); // Interrupt Enable Register at 0x0C (enable GPIO[0] interrupt)
    apb_write(6'd6, 32'hFF); // Clear any pending interrupts

    // Generate an edge on GPIO[0]
    gpio_drive[0] = 1'b0;
    gpio_drive_en[0] = 1'b1; // Enable driving GPIO[0]
    repeat (3) @ (posedge pclk);
    gpio_drive[0] = 1'b1;
    repeat (3) @ (posedge pclk); // Wait for edge detection

    // Check that interrupt is set
    apb_read(6'd6, read_data); // Interrupt State Register at 0x18
    if (read_data[0] !== 1'b1) begin
      $display("FAIL: Interrupt not set on GPIO[0]");
    end else begin
      $display("PASS: Interrupt set on GPIO[0]");
    end

    // Use software-controlled reset to clear interrupts
    apb_write(6'd9, 32'h1); // Write to Interrupt Control Register at 0x24
    #20; // Wait for interrupt reset

    // Verify that interrupt is cleared
    apb_read(6'd6, read_data);
    if (read_data[0] !== 1'b0) begin
      $display("FAIL: Interrupt not cleared by software-controlled reset");
    end else begin
      $display("PASS: Interrupt cleared by software-controlled reset");
    end

    // Disable GPIO[0] driving
    gpio_drive_en[0] = 1'b0;

    // Test 4: Combined Test - Changing Directions and Verifying Behavior
    $display("\nTest 4: Combined Test - Changing Directions and Verifying Behavior");
    // Change direction of GPIO[2] from input to output
    apb_write(6'd7, 32'hF4); // Update Direction Control Register (GPIO[2] as output)
    #20;

    // Write to Data Output Register
    apb_write(6'd1, 32'h04); // Set GPIO[2] high
    #20;

    // Verify that GPIO[2] is driven high
    if (gpio[2] !== 1'b1) begin
      $display("FAIL: GPIO[2] output mismatch after changing direction");
    end else begin
      $display("PASS: GPIO[2] output is high after changing direction to output");
    end

    // Change direction of GPIO[7] from output to input
    apb_write(6'd7, 32'h74); // Update Direction Control Register (GPIO[7] as input)
    #20;

    // Drive GPIO[7] from testbench
    gpio_drive[7] = 1'b1;
    gpio_drive_en[7] = 1'b1;
    repeat (3) @ (posedge pclk); // Wait for synchronization

    // Read Input Data Register
    apb_read(6'd0, read_data);
    if (read_data[7] !== 1'b1) begin
      $display("FAIL: GPIO[7] input data mismatch after changing direction");
    end else begin
      $display("PASS: GPIO[7] input data is high after changing direction to input");
    end

    // Disable GPIO[7] driving
    gpio_drive_en[7] = 1'b0;

    // Test 5: Verify Module Does Not Respond When Powered Down
    $display("\nTest 5: Verify Module Does Not Respond When Powered Down");
    // Power down the module
    apb_write(6'd8, 32'h1); // Power Down Register at 0x20
    #20;

    // Try to write to Direction Control Register while powered down
    apb_write(6'd7, 32'hFF); // Attempt to set all GPIOs as outputs
    #20;
    apb_read(6'd7, read_data);
    if (read_data[GPIO_WIDTH-1:0] !== 8'h74) begin
      $display("FAIL: Direction Control Register changed during power-down");
    end else begin
      $display("PASS: Direction Control Register did not change during power-down");
    end

    // Power up the module
    apb_write(6'd8, 32'h0); // Power Down Register at 0x20
    #20;

    // Verify that module responds again
    apb_write(6'd7, 32'hFF); // Set all GPIOs as outputs
    apb_read(6'd7, read_data);
    if (read_data[GPIO_WIDTH-1:0] !== 8'hFF) begin
      $display("FAIL: Module did not respond after power-up");
    end else begin
      $display("PASS: Module responds correctly after power-up");
    end

    // Test 6: Verify Interrupts Do Not Occur When Powered Down
    $display("\nTest 6: Verify Interrupts Do Not Occur When Powered Down");
    // Configure interrupts on GPIO[1]
    apb_write(6'd4, 32'h02); // Interrupt Type Register (edge-triggered on GPIO[1])
    apb_write(6'd5, 32'h00); // Interrupt Polarity Register (active high)
    apb_write(6'd3, 32'h02); // Interrupt Enable Register (enable GPIO[1] interrupt)
    apb_write(6'd6, 32'hFF); // Clear any pending interrupts

    // Power down the module
    apb_write(6'd8, 32'h1); // Power Down Register at 0x20
    #20;

    // Generate an edge on GPIO[1]
    gpio_drive[1] = 1'b0;
    gpio_drive_en[1] = 1'b1;
    repeat (3) @ (posedge pclk);
    gpio_drive[1] = 1'b1;
    repeat (3) @ (posedge pclk);

    // Verify that no interrupt is set
    apb_read(6'd6, read_data);
    if (read_data[1] !== 1'b0) begin
      $display("FAIL: Interrupt occurred during power-down");
    end else begin
      $display("PASS: No interrupt occurred during power-down");
    end

    // Power up the module
    apb_write(6'd8, 32'h0); // Power Down Register at 0x20
    repeat (3) @ (posedge pclk);

    // Generate edge again
    gpio_drive[1] = 1'b0;
    repeat (3) @ (posedge pclk);
    gpio_drive[1] = 1'b1;
    repeat (3) @ (posedge pclk);

    // Verify that interrupt is now set
    apb_read(6'd6, read_data);
    if (read_data[1] !== 1'b1) begin
      $display("FAIL: Interrupt not set after power-up");
    end else begin
      $display("PASS: Interrupt set after power-up");
    end

    // Disable GPIO[1] driving
    gpio_drive_en[1] = 1'b0;

    // End of Testbench
    $display("\nTestbench completed successfully");
    $finish;
  end

endmodule

input.verif/tb_arithmetic_progression_generato:
module tb_arithmetic_progression_generator;

    // Sequence 1 parameters
    parameter DATA_WIDTH_1 = 16;
    parameter SEQUENCE_LENGTH_1 = 5;
    localparam WIDTH_OUT_VAL_1 = $clog2(SEQUENCE_LENGTH_1) + DATA_WIDTH_1; // Bit width of out_val to prevent overflow


    // Sequence 2 parameters
    parameter DATA_WIDTH_2 = 8;
    parameter SEQUENCE_LENGTH_2 = 10;
    logic [11 : 0] final_value = 'h9F6;
    localparam WIDTH_OUT_VAL_2 = $clog2(SEQUENCE_LENGTH_2) + DATA_WIDTH_2; // Bit width of out_val to prevent overflow


    // Sequence 3 parameters
    parameter DATA_WIDTH_3 = 12;
    parameter SEQUENCE_LENGTH_3 = 7;
    localparam WIDTH_OUT_VAL_3 = $clog2(SEQUENCE_LENGTH_3) + DATA_WIDTH_3; // Bit width of out_val to prevent overflow


    // Testbench signals
    logic clk;
    logic resetn;
    logic enable;
    logic [15:0] start_val;  // Max width needed across test cases
    logic [15:0] step_size;  // Max width needed across test cases
    logic done_1, done_2, done_3; // Done signals for each sequence
    logic [WIDTH_OUT_VAL_1-1:0] out_val_1;
    logic [WIDTH_OUT_VAL_2-1:0] out_val_2;
    logic [WIDTH_OUT_VAL_3-1:0] out_val_3;
    int cycle_counter; // Cycle counter for tracking clock cycles

    // Instantiate DUTs for each sequence
    arithmetic_progression_generator #(
        .DATA_WIDTH(DATA_WIDTH_1),
        .SEQUENCE_LENGTH(SEQUENCE_LENGTH_1)
    ) dut1 (
        .clk(clk),
        .resetn(resetn),
        .enable(enable),
        .start_val(start_val[DATA_WIDTH_1-1:0]),
        .step_size(step_size[DATA_WIDTH_1-1:0]),
        .out_val(out_val_1),
        .done(done_1)
    );

    arithmetic_progression_generator #(
        .DATA_WIDTH(DATA_WIDTH_2),
        .SEQUENCE_LENGTH(SEQUENCE_LENGTH_2)
    ) dut2 (
        .clk(clk),
        .resetn(resetn),
        .enable(enable),
        .start_val(start_val[DATA_WIDTH_2-1:0]),
        .step_size(step_size[DATA_WIDTH_2-1:0]),
        .out_val(out_val_2),
        .done(done_2)
    );

    arithmetic_progression_generator #(
        .DATA_WIDTH(DATA_WIDTH_3),
        .SEQUENCE_LENGTH(SEQUENCE_LENGTH_3)
    ) dut3 (
        .clk(clk),
        .resetn(resetn),
        .enable(enable),
        .start_val(start_val[DATA_WIDTH_3-1:0]),
        .step_size(step_size[DATA_WIDTH_3-1:0]),
        .out_val(out_val_3),
        .done(done_3)
    );

    // Clock generation
    initial begin
        clk = 0;
        forever #5 clk = ~clk; // 10 ns clock period
    end

    // Test procedure
    initial begin
        // Test sequence 1, normal testing
        $display("\nRunning Test Sequence 1: DATA_WIDTH=%0d, SEQUENCE_LENGTH=%0d, Start Value=%0d, Step Size=%0d", 
                 DATA_WIDTH_1, SEQUENCE_LENGTH_1, 10, 15);
        run_test(1, 10, 15); // start_val = 10, step_size = 15

        // Test sequence 2, check for overflow 
        $display("\nRunning Test Sequence 2: DATA_WIDTH=%0d, SEQUENCE_LENGTH=%0d, Start Value=%0d, Step Size=%0d", 
                 DATA_WIDTH_2, SEQUENCE_LENGTH_2, 8'hFF , 8'hFF);
        run_test(2, 8'hFF, 8'hFF); // start_val = 5, step_size = 3

        // Test sequence 3
        $display("\nRunning Test Sequence 3: DATA_WIDTH=%0d, SEQUENCE_LENGTH=%0d, Start Value=%0d, Step Size=%0d", 
                 DATA_WIDTH_3, SEQUENCE_LENGTH_3, 20, 7);
        run_test(3, 20, 7); // start_val = 20, step_size = 7

        // End simulation
        $finish;
    end

    // Task to run individual test sequences
    task run_test(input int sequence_id, input int s_val, input int step);
        begin
            // Reset cycle counter for each sequence
            cycle_counter = 0;

            resetn = 0;
            enable = 0;
            start_val = s_val;
            step_size = step;

            // Apply reset
            #10 resetn = 1;

            // Start the progression generator
            #10 enable = 1;

            // Monitor progress for the active sequence
            if (sequence_id == 1) begin
                while (!done_1) begin
                    @(posedge clk);
                    cycle_counter++;
                    $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | out_val: %0d | done: %b | enable: %b", 
                             cycle_counter, $time, resetn, s_val, step, out_val_1, done_1, enable);
                end
                @(posedge clk);
                cycle_counter++;
                $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | Final out_val: %0d | done: %b | enable: %b", 
                         cycle_counter, $time, resetn, s_val, step, out_val_1, done_1, enable);
                assert (out_val_1 == 'h46 ) else $error("Wrong output");

            end else if (sequence_id == 2) begin
                while (!done_2) begin
                    @(posedge clk);
                    cycle_counter++;
                    $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | out_val: %0d | done: %b | enable: %b", 
                             cycle_counter, $time, resetn, s_val, step, out_val_2, done_2, enable);
                end
                @(posedge clk);
                cycle_counter++;
                $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | Final out_val: %0d | done: %b | enable: %b", 
                         cycle_counter, $time, resetn, s_val, step, out_val_2, done_2, enable);
                assert (out_val_2 == final_value ) else $error("Overflow occured!");

            end else if (sequence_id == 3) begin
                while (!done_3) begin
                    @(posedge clk);
                    cycle_counter++;
                    $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | out_val: %0d | done: %b | enable: %b", 
                             cycle_counter, $time, resetn, s_val, step, out_val_3, done_3, enable);
                end
                @(posedge clk);
                cycle_counter++;
                $display("Cycle: %0d | Time: %0t | resetn: %b | Start Value: %0d | Step Size: %0d | Final out_val: %0d | done: %b | enable: %b", 
                         cycle_counter, $time, resetn, s_val, step, out_val_3, done_3, enable);
            end

            // Disable and reset for the next test
            #10 enable = 0;
            resetn = 0;
            #10;
        end
    endtask

    // Waveform dumping and simulation control
    initial begin
        $dumpfile("dump.vcd");
        $dumpvars(0, tb_arithmetic_progression_generator);
        #1000 $finish;
    end

endmodule

input.verif/axi_tap_tb.sv:
`timescale 1ns/1ps

module axi_tap_tb;

    // Parameters
    localparam ADDR_WIDTH = 32;
    localparam DATA_WIDTH = 32;

    // Clock and Reset
    logic clk_i;
    logic rst_i;

    // AXI Master Interface (Inputs)
    logic                        inport_awvalid_i;
    logic [ADDR_WIDTH-1:0]       inport_awaddr_i;
    logic                        inport_wvalid_i;
    logic [DATA_WIDTH-1:0]       inport_wdata_i;
    logic [3:0]                  inport_wstrb_i;
    logic                        inport_bready_i;
    logic                        inport_arvalid_i;
    logic [ADDR_WIDTH-1:0]       inport_araddr_i;
    logic                        inport_rready_i;

