        inport_wstrb_i = 0;
        inport_arvalid_i = 0;
        inport_araddr_i = 0;
        inport_rready_i = 1;
        outport_peripheral0_bvalid_i = 0;

        #20;
        rst_i = 0;
        $display("[%0t] Reset deasserted.", $time);
        #125;
        inport_awvalid_i = 1;
        inport_awaddr_i = 32'h9000_0000;
        inport_wvalid_i = 1;
        inport_wdata_i = 32'hDEAD_BEEF;
        inport_wstrb_i = 4'hF;
        expected_response = 2'b11;

        #20;
