    tb_penable = 1;
    @(posedge tb_pclk);
    tb_penable = 0;
    tb_pselx = 0;
    repeat (2) @(posedge tb_pclk);

    if (tb_prdata == tb_pwdata)
        $display("TEST PASSED: DATA_REG read/write successful.");
