input.rtl/csr_apb_interface.sv:
module csr_apb_interface (
    input                    pclk,              // Clock input for synchronization
    input                    presetn,           // Active-low asynchronous reset input
    input [31:0]             paddr,             // APB address bus, 32-bit for register addressing
    input                    pselx,             // APB peripheral select signal
    input                    penable,           // APB enable signal for transactions
    input                    pwrite,            // APB write enable signal
    input [31:0]             pwdata,            // APB write data bus

    output reg               pready,            // APB ready signal, indicates end of transaction
    output reg [31:0]        prdata,            // APB read data bus
    output reg               pslverr,           // APB slave error signal

    output [1:0]             debug_state        // Debug output to monitor state
);

    // ----------------------------------------
    // Register Addresses
    // ----------------------------------------
    localparam DATA_REG       = 32'h10; // Data register
    localparam CONTROL_REG    = 32'h14; // Control register
    localparam INTERRUPT_REG  = 32'h18; // Interrupt configuration register
    localparam ISR_REG        = 32'h1C; // Interrupt status register

    // ----------------------------------------
    // State Machine States
    // ----------------------------------------
    localparam IDLE           = 2'b00; // Idle state
    localparam SETUP          = 2'b01; // Setup state
    localparam READ_STATE     = 2'b10; // Read operation state
    localparam WRITE_STATE    = 2'b11; // Write operation state

    // ----------------------------------------
    // Internal State Registers
    // ----------------------------------------
    reg [1:0]                 present_state, next_state; 

    // Signals for state transitions and outputs
    reg                       next_pready;
    reg [31:0]                next_prdata;
    reg                       next_pslverr;

    // Internal Storage Registers
    reg [9:0]                 data1, next_data1;
    reg [9:0]                 data2, next_data2;
    reg [11:0]                data_reserved, next_data_reserved;

    reg                       enable, next_enable;     
    reg                       mode, next_mode;         
    reg [29:0]                control_reserved, next_control_reserved;

    reg                       overflow_ie, next_overflow_ie; 
    reg                       sign_ie, next_sign_ie;
    reg                       parity_ie, next_parity_ie;
    reg                       zero_ie, next_zero_ie;
    reg [27:0]                interrupt_reserved, next_interrupt_reserved;

    reg                       overflow_is, next_overflow_is; 
    reg                       sign_is, next_sign_is;
    reg                       parity_is, next_parity_is;
    reg                       zero_is, next_zero_is;

    assign debug_state = present_state;
    wire write_protected = (paddr == ISR_REG);

    always @ (*) begin
        next_pready           = pready;
        next_prdata           = prdata;
        next_pslverr          = pslverr;

        next_data1            = data1;
        next_data2            = data2;
        next_data_reserved    = data_reserved;

        next_enable           = enable;
        next_mode             = mode;
        next_control_reserved = control_reserved;

        next_overflow_ie      = overflow_ie;
        next_sign_ie          = sign_ie;
        next_parity_ie        = parity_ie;
        next_zero_ie          = zero_ie;
        next_interrupt_reserved = interrupt_reserved;

        next_overflow_is      = overflow_is;
        next_sign_is          = sign_is;
        next_parity_is        = parity_is;
        next_zero_is          = zero_is;

        next_state            = present_state;

        case (present_state)
            IDLE: begin
                if (pselx)
                    next_state = SETUP;
            end

            SETUP: begin
                if (penable && pwrite && !write_protected)
                    next_state = WRITE_STATE;
                else if (penable && !pwrite)
                    next_state = READ_STATE;
                else if (penable && write_protected)
                    next_pslverr = 1'b1; 
            end

            READ_STATE: begin
                if (pready) begin
                    next_state = IDLE;
                    next_pready = 1'b0;
                end else begin
                    next_pready = 1'b1;
                    case (paddr)
                        DATA_REG:      next_prdata = {data_reserved, data1, data2};
                        CONTROL_REG:   next_prdata = {control_reserved, enable, mode};
                        INTERRUPT_REG: next_prdata = {interrupt_reserved, overflow_ie, sign_ie, parity_ie, zero_ie};
                        ISR_REG:       next_prdata = {28'b0, overflow_is, sign_is, parity_is, zero_is};
                        default:       next_pslverr = 1'b1; 
                    endcase
                end
            end

            WRITE_STATE: begin
                if (pready) begin
                    next_state = IDLE;
                    next_pready = 1'b0;
                end else begin
                    next_pready = 1'b1;
                    case (paddr)
                        DATA_REG: begin
                            next_data1            = pwdata[19:10];
                            next_data2            = pwdata[9:0];
                            next_data_reserved    = pwdata[31:20];
                        end
                        CONTROL_REG: begin
                            next_enable           = pwdata[1];
                            next_mode             = pwdata[0];
                            next_control_reserved = pwdata[31:2];
                        end
                        INTERRUPT_REG: begin
                            next_overflow_ie      = pwdata[3];
                            next_sign_ie          = pwdata[2];
                            next_parity_ie        = pwdata[1];
                            next_zero_ie          = pwdata[0];
                            next_interrupt_reserved = pwdata[31:4];

                            next_overflow_is      = pwdata[3] ? 1'b0 : overflow_is;
                            next_sign_is          = pwdata[2] ? 1'b0 : sign_is;
                            next_parity_is        = pwdata[1] ? 1'b0 : parity_is;
                            next_zero_is          = pwdata[0] ? 1'b0 : zero_is;
                        end
                        default: next_pslverr = 1'b1; 
                    endcase
                end
            end
        endcase
    end

    always @ (posedge pclk or negedge presetn) begin
        if (!presetn) begin
            pready               <= 1'b0;
            prdata               <= 32'h0;
            pslverr              <= 1'b0;

            present_state        <= IDLE;
            data1                <= 10'd0;
            data2                <= 10'd0;
            data_reserved        <= 12'd0;

            enable               <= 1'b0;
            mode                 <= 1'b0;
            control_reserved     <= 30'd0;

            overflow_ie          <= 1'b0;
            sign_ie              <= 1'b0;
            parity_ie            <= 1'b0;
            zero_ie              <= 1'b0;
            interrupt_reserved   <= 28'd0;

            overflow_is          <= 1'b0;
            sign_is              <= 1'b0;
            parity_is            <= 1'b0;
            zero_is              <= 1'b0;
        end else begin
            present_state        <= next_state;
            pready               <= next_pready;
            prdata               <= next_prdata;
            pslverr              <= next_pslverr;

            data1                <= next_data1;
            data2                <= next_data2;
            data_reserved        <= next_data_reserved;

            enable               <= next_enable;
            mode                 <= next_mode;
            control_reserved     <= next_control_reserved;

            overflow_ie          <= next_overflow_ie;
            sign_ie              <= next_sign_ie;
            parity_ie            <= next_parity_ie;
            zero_ie              <= next_zero_ie;
            interrupt_reserved   <= next_interrupt_reserved;

            overflow_is          <= next_overflow_is;
            sign_is              <= next_sign_is;
            parity_is            <= next_parity_is;
            zero_is              <= next_zero_is;
        end
    end

endmodule

input.rtl/cvdp_copilot_decode_firstbit.sv:
module cvdp_copilot_decode_firstbit #(
    parameter integer InWidth_g = 32,
    parameter InReg_g = 1,
    parameter OutReg_g = 1,
    parameter integer PlRegs_g = 1,
    parameter OutputFormat_g = 0  // 0: Binary, 1: One-Hot Encoding
)(
    input wire Clk,
    input wire Rst,
    input wire [InWidth_g-1:0] In_Data,
    input wire In_Valid,

    output reg [InWidth_g-1:0] Out_FirstBit,   // Binary index or one-hot bit
    output reg Out_Found,
    output reg Out_Valid
);

    // Local parameters
    localparam integer BinBits_c = $clog2(InWidth_g);

    // Internal signals
    reg [InWidth_g-1:0] In_Data_r;
    reg In_Valid_r;
    reg [PlRegs_g:0] Valid_pipeline;
    reg [PlRegs_g:0] Found_pipeline;
    reg [BinBits_c-1:0] FirstBit_pipeline [PlRegs_g:0];
    reg [InWidth_g-1:0] OneHotBit_pipeline [PlRegs_g:0];

    // Optional input register
    generate
    if (InReg_g == 1) begin : input_reg_block
        always @(posedge Clk or posedge Rst) begin
            if (Rst) begin
                In_Data_r <= {InWidth_g{1'b0}};
                In_Valid_r <= 1'b0;
            end else begin
                In_Data_r <= In_Data;
                In_Valid_r <= In_Valid;
            end
        end
    end else begin : no_input_reg_block
        always @(*) begin
            In_Data_r = In_Data;
            In_Valid_r = In_Valid;
        end
    end
    endgenerate

    // Function to find the index of the first '1' bit from LSB to MSB
    function [BinBits_c-1:0] find_first_one(input [InWidth_g-1:0] data_in);
        integer i;
        reg found;
        begin
            find_first_one = {BinBits_c{1'b0}};
            found = 0;
            for (i = 0; i < InWidth_g; i = i + 1) begin
                if (!found && data_in[i]) begin
                    find_first_one = i[BinBits_c-1:0];
                    found = 1;
                end
            end
        end
    endfunction

    // Function to generate one-hot encoding of the first set bit
    function [InWidth_g-1:0] one_hot_encode(input [BinBits_c-1:0] binary_index);
        begin
            one_hot_encode = {InWidth_g{1'b0}};
            one_hot_encode[binary_index] = 1'b1;
        end
    endfunction

    // Stage 0: Compute the first '1' bit position and its one-hot encoding
    always @(posedge Clk or posedge Rst) begin
        if (Rst) begin
            Valid_pipeline[0] <= 1'b0;
            Found_pipeline[0] <= 1'b0;
            FirstBit_pipeline[0] <= {BinBits_c{1'b0}};
            OneHotBit_pipeline[0] <= {InWidth_g{1'b0}};
        end else begin
            Valid_pipeline[0] <= In_Valid_r;
            Found_pipeline[0] <= |In_Data_r;
            if (|In_Data_r) begin
                FirstBit_pipeline[0] <= find_first_one(In_Data_r);
                OneHotBit_pipeline[0] <= one_hot_encode(find_first_one(In_Data_r));
            end else begin
                FirstBit_pipeline[0] <= {BinBits_c{1'b0}};
                OneHotBit_pipeline[0] <= {InWidth_g{1'b0}};
            end
        end
    end

    // Pipeline stages
    genvar k;
    generate
        for (k = 1; k <= PlRegs_g; k = k + 1) begin : pipeline_stages
            always @(posedge Clk or posedge Rst) begin
                if (Rst) begin
                    Valid_pipeline[k] <= 1'b0;
                    Found_pipeline[k] <= 1'b0;
                    FirstBit_pipeline[k] <= {BinBits_c{1'b0}};
                    OneHotBit_pipeline[k] <= {InWidth_g{1'b0}};
                end else begin
                    Valid_pipeline[k] <= Valid_pipeline[k-1];
                    Found_pipeline[k] <= Found_pipeline[k-1];
                    FirstBit_pipeline[k] <= FirstBit_pipeline[k-1];
                    OneHotBit_pipeline[k] <= OneHotBit_pipeline[k-1];
                end
            end
        end
    endgenerate

    // Optional output register
    generate
    if (OutReg_g == 1) begin : output_reg_block
        always @(posedge Clk or posedge Rst) begin
            if (Rst) begin
                Out_Valid <= 1'b0;
                Out_Found <= 1'b0;
                Out_FirstBit <= {InWidth_g{1'b0}};
            end else begin
                Out_Valid <= Valid_pipeline[PlRegs_g];
                Out_Found <= Found_pipeline[PlRegs_g];
                if (OutputFormat_g == 0) begin
                    // Binary encoding: Zero-extend to match width
                    Out_FirstBit <= {{(InWidth_g - BinBits_c){1'b0}}, FirstBit_pipeline[PlRegs_g]};
                end else begin
                    // One-hot encoding
                    Out_FirstBit <= OneHotBit_pipeline[PlRegs_g];
                end
            end
        end
    end else begin : no_output_reg_block
        always @(*) begin
            Out_Valid = Valid_pipeline[PlRegs_g];
            Out_Found = Found_pipeline[PlRegs_g];
            if (OutputFormat_g == 0) begin
                // Binary encoding: Zero-extend to match width
                Out_FirstBit = {{(InWidth_g - BinBits_c){1'b0}}, FirstBit_pipeline[PlRegs_g]};
            end else begin
                // One-hot encoding
                Out_FirstBit = OneHotBit_pipeline[PlRegs_g];
            end
        end
    end
    endgenerate

endmodule

input.verif/tb_cvdp_copilot_decode_firstbit.sv:
`timescale 1ns/1ps

module tb_cvdp_copilot_decode_firstbit;

    // Parameters
    parameter integer InWidth_g = 32;
    parameter integer InReg_g = 1;        // Enable input register
    parameter integer OutReg_g = 1;       // Enable output register
    parameter integer PlRegs_g = 1;       // Number of pipeline stages

    // Clock period (adjust as needed)
    localparam CLK_PERIOD = 10;

    // Signals
    reg Clk;
    reg Rst;
    reg [InWidth_g-1:0] In_Data;
    reg In_Valid;

    // Outputs for binary encoding
    wire [InWidth_g-1:0] Out_FirstBit_Binary;
    wire Out_Found_Binary;
    wire Out_Valid_Binary;

    // Outputs for one-hot encoding
    wire [InWidth_g-1:0] Out_FirstBit_OneHot;
    wire Out_Found_OneHot;
    wire Out_Valid_OneHot;

    // Instantiate the Device Under Test (DUT) with binary output
    cvdp_copilot_decode_firstbit #(
        .InWidth_g(InWidth_g),
        .InReg_g(InReg_g),
        .OutReg_g(OutReg_g),
        .PlRegs_g(PlRegs_g),
        .OutputFormat_g(0)  // Binary encoding
    ) dut_binary (
        .Clk(Clk),
        .Rst(Rst),
        .In_Data(In_Data),
        .In_Valid(In_Valid),
        .Out_FirstBit(Out_FirstBit_Binary),
        .Out_Found(Out_Found_Binary),
        .Out_Valid(Out_Valid_Binary)
    );

    // Instantiate the Device Under Test (DUT) with one-hot output
    cvdp_copilot_decode_firstbit #(
        .InWidth_g(InWidth_g),
        .InReg_g(InReg_g),
        .OutReg_g(OutReg_g),
        .PlRegs_g(PlRegs_g),
        .OutputFormat_g(1)  // One-hot encoding
    ) dut_onehot (
        .Clk(Clk),
        .Rst(Rst),
        .In_Data(In_Data),
        .In_Valid(In_Valid),
        .Out_FirstBit(Out_FirstBit_OneHot),
        .Out_Found(Out_Found_OneHot),
        .Out_Valid(Out_Valid_OneHot)
    );

    // Clock generation
    initial begin
        Clk = 0;
        forever #(CLK_PERIOD/2) Clk = ~Clk;
    end

    // Test stimulus
    initial begin
        // VCD Dumping
        $dumpfile("tb_cvdp_copilot_decode_firstbit.vcd"); // Specify the VCD file name
        $dumpvars(0, tb_cvdp_copilot_decode_firstbit);    // Dump all variables in the testbench        

        // Initialize inputs
        Rst = 1;
        In_Data = {InWidth_g{1'b0}};
        In_Valid = 0;

        // Wait for reset
        #(CLK_PERIOD*5);
        Rst = 0;

        // Apply test vectors
        apply_test_vector(32'h00000000); // No bits set
        apply_test_vector(32'h00000001); // First bit set
        apply_test_vector(32'h00000002); // Second bit set
        apply_test_vector(32'h80000000); // Last bit set
        apply_test_vector(32'h00010000); // Middle bit set
        apply_test_vector(32'hFFFFFFFF); // All bits set
        apply_test_vector(32'hFFFFFFFE); // All but first bit set
        apply_test_vector(32'h7FFFFFFF); // All but last bit set
        apply_test_vector(32'h00008000); // Random bit set
        apply_test_vector(32'h00000008); // Another random bit set
        // Adjusted to 32-bit width
        apply_test_vector(32'h00012000); // Another random bit set

        // Finish simulation after some time
        #(CLK_PERIOD*20);
        $finish;
    end

    // Task to apply a test vector
    task apply_test_vector(input [InWidth_g-1:0] data_in);
        integer expected_index;
        reg [InWidth_g-1:0] expected_onehot;
        begin
            // Apply input data
            @(negedge Clk);
            In_Data = data_in;
            In_Valid = 1;

            @(negedge Clk);
            In_Valid = 0;

            // Wait for the output to become valid, accounting for pipeline latency
            wait (Out_Valid_Binary && Out_Valid_OneHot);

            // Calculate expected index and one-hot encoding
            expected_index = find_first_set_bit(data_in);
            expected_onehot = one_hot_encode(expected_index);

            // Display and check the result for binary encoding
            if (Out_Found_Binary) begin
                $display("Binary Encoding - Time %t: Input = %h, Expected Index = %d, DUT Output = %d",
                         $time, data_in, expected_index, Out_FirstBit_Binary[($clog2(InWidth_g)-1):0]);
                if (Out_FirstBit_Binary[($clog2(InWidth_g)-1):0] != expected_index) begin
                    $display("ERROR: Mismatch in binary first set bit index!");
                end
            end else begin
                $display("Binary Encoding - Time %t: Input = %h, No set bits found (as expected)", $time, data_in);
                if (expected_index != -1) begin
                    $display("ERROR: DUT did not find the first set bit when it should have!");
                end
            end

            // Display and check the result for one-hot encoding
            if (Out_Found_OneHot) begin
                $display("One-Hot Encoding - Time %t: Input = %h, Expected One-Hot = %h, DUT Output = %h",
                         $time, data_in, expected_onehot, Out_FirstBit_OneHot);
                if (Out_FirstBit_OneHot != expected_onehot) begin
                    $display("ERROR: Mismatch in one-hot first set bit!");
                end
            end else begin
                $display("One-Hot Encoding - Time %t: Input = %h, No set bits found (as expected)", $time, data_in);
                if (expected_index != -1) begin
                    $display("ERROR: DUT did not find the first set bit when it should have!");
                end
            end

            // Wait before applying next test vector
            #(CLK_PERIOD*2);
        end
    endtask

    // Function to find the expected first set bit index
    function integer find_first_set_bit(input [InWidth_g-1:0] data_in);
        integer idx;
        reg found;
        begin
            find_first_set_bit = -1; // Default to -1 if no bits are set
            found = 0;
            for (idx = 0; idx < InWidth_g; idx = idx + 1) begin
                if (!found && data_in[idx]) begin
                    find_first_set_bit = idx;
                    found = 1; // Set the flag to indicate the first set bit is found
                end
            end
        end
    endfunction

    // Function to generate expected one-hot encoding
    function [InWidth_g-1:0] one_hot_encode(input integer index);
        begin
            if (index >= 0 && index < InWidth_g) begin
                one_hot_encode = {InWidth_g{1'b0}};
                one_hot_encode[index] = 1'b1;
            end else begin
                one_hot_encode = {InWidth_g{1'b0}};
            end
        end
    endfunction

endmodule

