module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);

  // Internal memory and pointer
  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  // Memory array to store data
  reg [$clog2(FILO_DEPTH)-1:0] top;  // Stack pointer


  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in;
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top]       <= data_in;
          top               <= top + 1;
          feedthrough_valid <= 0;
        end


        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;
            feedthrough_valid <= 0;
          end else begin
            top <= top - 1;
            data_out <= memory[top-1];
          end
        end
      end


      empty <= (top == 0);
      full  <= (top == (FILO_DEPTH));
    end
  end
endmodule

input.rtl/fixed_priority_arbiter.sv:
module fixed_priority_arbiter(
    input clk,             // Clock signal
    input reset,           // Active high reset signal
    input [7:0] req,       // 8-bit request signal; each bit represents a request from a different source
    output reg [7:0] grant // 8-bit grant signal; only one bit will be set high based on priority
); 

    always @(posedge clk or posedge reset) begin

        if (reset) 
            grant <= 8'b00000000;
        else begin
            if (req[0])
                grant <= 8'b00000001;
            else if (req[1])
                grant <= 8'b00000010;
            else if (req[2])
                grant <= 8'b00000100;
            else if (req[3])
                grant <= 8'b00001000;
            else if (req[4])
                grant <= 8'b00010000;
            else if (req[5])
                grant <= 8'b00100000;
            else if (req[6])
                grant <= 8'b01000000;
            else if (req[7])
                grant <= 8'b10000000;
            else
                grant <= 8'b00000000;
        end
    end
endmodule

input.verif/fixed_priority_arbiter_tb.sv:
`timescale 1ns / 1ps
module fixed_priority_arbiter_tb;

    // Inputs
    reg clk;
    reg reset;
    reg [7:0] req;

    // Outputs
    wire [7:0] grant;

    // Instantiate the Device Under Test (DUT)
    fixed_priority_arbiter dut (
        .clk(clk),
        .reset(reset),
        .req(req),
        .grant(grant)
    );

    always #5 clk = ~clk;

    task apply_reset;
        begin
            reset = 1;
            #10;            
            reset = 0;
        end
    endtask

    // Task: Drive request and check expected grant
    task drive_request(input [7:0] request, input [7:0] expected_grant);
        begin
            req = request;          
            #10;                    
            if (grant !== expected_grant) begin
                $display("ERROR: Unexpected grant value at time %0t | req=%b | expected grant=%b | observed grant=%b",
                         $time, req, expected_grant, grant);
            end else begin
                $display("PASS: Correct grant value at time %0t | req=%b | grant=%b", $time, req, grant);
            end
        end
    endtask

    // Test procedure
    initial begin
        // Initialize signals
        clk = 0;
        req = 8'b00000000;

        // Apply reset
        apply_reset;

        // Test Case 1: Single request
        drive_request(8'b00000001, 8'b00000001);  
        drive_request(8'b00000010, 8'b00000010);  
