   function automatic integer gcd(input integer x, input integer y);
      begin
         x = (x < 0) ? -x : x; 
         y = (y < 0) ? -y : y;
         while (y != 0) begin
            integer t;
            t = y;
            y = x % y;
            x = t;
         end
         gcd = x;
      end
   endfunction

   function automatic integer compute_gcd(input integer x, input integer y, input integer z);
      integer temp_gcd_1;
      begin
         temp_gcd_1 = gcd(x, y);
         compute_gcd = gcd(temp_gcd_1, z);
      end
   endfunction

