              end
              else begin
                always_ff @(posedge clk)
                  if (srst)
                    add_stage[((gv4*ROW_A*COL_B*HALF_MODIFIED_COL_A)+((((gv1*COL_B)+gv2)*HALF_MODIFIED_COL_A)+gv3))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
                  else if ((HALF_MODIFIED_COL_A > 1) && (gv3 < (HALF_MODIFIED_COL_A/2)))
