          for (gv3 = 0 ; gv3 < MODIFIED_COL_A ; gv3++) begin: out_add_gb
            always_ff @(posedge clk)
              if (srst)
                matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0;
