            $display("Write operation successful on Port B. Addr=%h, Data=%h", b_addr, b_wdata);
         end

         @(negedge clk);
         b_we    = 0;
         b_oe    = 1;

         @(posedge clk);
         @(posedge clk);

         if (b_rdata !== RAM[b_addr]) begin
            $display("Error: Read operation failed on Port B. Addr=%h, Expected=%h, Actual=%h", b_addr, RAM[b_addr], b_rdata);
