module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank      // BLANK to VGA connector
);

    parameter logic [9:0] H_ACTIVE  =  10'd639;
    parameter logic [9:0] H_FRONT   =  10'd15;
    parameter logic [9:0] H_PULSE   =  10'd95;
    parameter logic [9:0] H_BACK    =  10'd47;
    parameter logic [9:0] V_ACTIVE  =  10'd479;
    parameter logic [9:0] V_FRONT   =  10'd9;
    parameter logic [9:0] V_PULSE   =  10'd1;
    parameter logic [9:0] V_BACK    =  10'd32;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic hsync_reg;
    logic vsync_reg;
    logic [7:0] red_reg;
    logic [7:0] green_reg;
    logic [7:0] blue_reg;
    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;
    logic [7:0] h_state;
    logic [7:0] v_state;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter <= (h_counter == H_ACTIVE) ? 10'd0 : (h_counter + 10'd1);
                    hsync_reg <= HIGH;
                    line_done <= LOW;
                    h_state <= (h_counter == H_ACTIVE) ? H_FRONT_STATE : H_ACTIVE_STATE;
                end
                H_FRONT_STATE: begin
                    h_counter <= (h_counter == H_FRONT) ? 10'd0 : (h_counter + 10'd1);
                    hsync_reg <= HIGH;
                    h_state <= (h_counter == H_FRONT) ? H_PULSE_STATE : H_FRONT_STATE;
                end
                H_PULSE_STATE: begin
                    h_counter <= (h_counter == H_PULSE) ? 10'd0 : (h_counter + 10'd1);
                    hsync_reg <= LOW;
                    h_state <= (h_counter == H_PULSE) ? H_BACK_STATE : H_PULSE_STATE;
                end
                H_BACK_STATE: begin
                    h_counter <= (h_counter == H_BACK) ? 10'd0 : (h_counter + 10'd1);
                    hsync_reg <= HIGH;
                    h_state <= (h_counter == H_BACK) ? H_ACTIVE_STATE : H_BACK_STATE;
                    line_done <= (h_counter == (H_BACK - 1)) ? HIGH : LOW;
                end
            endcase
            case (v_state)
                V_ACTIVE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_ACTIVE) ? 10'd0 : (v_counter + 10'd1);
                        v_state <= (v_counter == V_ACTIVE) ? V_FRONT_STATE : V_ACTIVE_STATE;
                    end
                    vsync_reg <= HIGH;
                end
                V_FRONT_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_FRONT) ? 10'd0 : (v_counter + 10'd1);
                        v_state <= (v_counter == V_FRONT) ? V_PULSE_STATE : V_FRONT_STATE;
                    end
                    vsync_reg <= HIGH;
                end
                V_PULSE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_PULSE) ? 10'd0 : (v_counter + 10'd1);
                        v_state <= (v_counter == V_PULSE) ? V_BACK_STATE : V_PULSE_STATE;
                    end
                    vsync_reg <= LOW;
                end
                V_BACK_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_BACK) ? 10'd0 : (v_counter + 10'd1);
                        v_state <= (v_counter == V_BACK) ? V_ACTIVE_STATE : V_BACK_STATE;
                    end
                    vsync_reg <= HIGH;
                end
            endcase
            if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
                red_reg   <= {color_in[7:5], 5'd0};
                green_reg <= {color_in[4:2], 5'd0};
                blue_reg  <= {color_in[1:0], 6'd0};
            end
            else begin
                red_reg   <= 8'd0;
                green_reg <= 8'd0;
                blue_reg  <= 8'd0;
            end
        end
    end

    assign hsync = hsync_reg;
    assign vsync = vsync_reg;
    assign red = red_reg;
    assign green = green_reg;
    assign blue = blue_reg;
    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync_reg & vsync_reg;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

output.subjective.txt:
The horizontal sync pulse is implemented in the H_PULSE_STATE of the horizontal state machine. In this state, the HSYNC signal (hsync_reg) is driven LOW. The relevant block is:

H_PULSE_STATE: begin
    h_counter <= (h_counter == H_PULSE) ? 10'd0 : (h_counter + 10'd1);
    hsync_reg <= LOW;
    h_state <= (h_counter == H_PULSE) ? H_BACK_STATE : H_PULSE_STATE;
end

